// readWritePin tracks accounts for which this process has accepted a write that
// may not have reached the replica yet.  Such accounts must not be served stale
// replica data: reads use the primary until the replica is observed to contain at
// least the balance returned by the write.
//
// A fixed time-based pin is not enough for read-after-write consistency because
// replication lag is variable (and can be much longer than the chosen TTL during
// network trouble).  The pin is therefore cleared by observing the replica catch
// up, not by the wall clock.
type readWritePin struct {
	mu         sync.Mutex
	minBalance map[string]int64
}

func newReadWritePin(_ time.Duration) *readWritePin {
	return &readWritePin{minBalance: make(map[string]int64)}
}

func (p *readWritePin) mark(account string, balance int64) {
	p.mu.Lock()
	defer p.mu.Unlock()
	if current, ok := p.minBalance[account]; !ok || balance > current {
		p.minBalance[account] = balance
	}
}

func (p *readWritePin) minimum(account string) (int64, bool) {
	p.mu.Lock()
	defer p.mu.Unlock()
	balance, ok := p.minBalance[account]
	return balance, ok
}

func (p *readWritePin) clearIfCaughtUp(account string, observedBalance int64) {
	p.mu.Lock()
	defer p.mu.Unlock()
	if current, ok := p.minBalance[account]; ok && observedBalance >= current {
		delete(p.minBalance, account)
	}
}

